-- Данные из файла gos_fin_fondy.xls по государственным внебюджетным фондам РФ.
-- Листы 1-5 загружены напрямую из таблиц; лист 6 использован только для добора рядов ПФР за 2001-2004 гг. по графику,
-- чтобы не дублировать значения 2005-2022 гг., уже присутствующие в листе 1.
-- В листе 4 значение за 2007 год по субвенциям ТФОМС нормализовано как 41823 из-за артефакта исходной ячейки Excel с вшитой сноской.
DROP TABLE IF EXISTS finance_gos_fin_fondy;

CREATE TABLE finance_gos_fin_fondy (
    id SERIAL PRIMARY KEY,
    source_sheet VARCHAR(10) NOT NULL,
    fund_name TEXT NOT NULL,
    period_year INTEGER NOT NULL,
    section_type VARCHAR(20) NOT NULL CHECK (section_type IN ('income', 'expense')),
    metric_name TEXT NOT NULL,
    metric_group TEXT NOT NULL,
    value_mln_rub NUMERIC,
    unit_name VARCHAR(50) NOT NULL DEFAULT 'млн рублей',
    UNIQUE (source_sheet, fund_name, period_year, metric_name)
);

